INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES ("", 72020, "vo_asb_0723", 72, 0, 0, "", "vo_asb", "", 21, "");
INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (1, 72021, "だからわたし、\n勇気を出して言ってみたんです！\nお友だちになりませんか、って。", 72, 1, 10, 0, 1, 0, 11, 0);
INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES ("", 72022, "", 72, 0, 0, "", 0, "", 91, "");
