INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (1, 72033, "そりゃそうですよね……\nいきなり前のめり過ぎ太郎でした……", 72, 1, 10, 0, 1, 0, 11, 0);
INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES ("", 72034, "", 72, 0, 0, "", 0, "", 91, "");
