INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (1, 82013, "その頃わたくしは、\nスカウトをお受けしておりました。\nミサト様いわく、わたくしには保育士の\n『天賦の才』があるそうで。", 82, 1, 10, 0, 1, 0, 11, 0);
INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES ("", 82014, "", 82, 0, 0, "", 0, "", 91, "");
INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES ("", 82015, "sad_talk_surprise", 82, "", 1, "", 1, "", 3, 0.2);
