INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (1, 82029, "柔和で、寛容で、お話のわかる……\n彼女こそ、真の保育士さんで\nいらっしゃいますね。", 82, 1, 10, 0, 1, 0, 11, 0);
INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES ("", 82030, "", 82, 0, 0, "", 0, "", 91, "");
