INSERT INTO `v1_447e44b64f7dd3521609535f53f87d7548dda9e44845b2b444e508b053d9d28c` VALUES (1, 82033, "……別れ際に、\n「また誘うわね～♪」と、\n同じく柔和な笑顔でおっしゃって\nおられたのがやや気にはなりますが……", 82, 1, 10, 0, 1, 0, 11, 0);
